let currentPage='dashboard';
const content=document.getElementById('content');
function kpi(label,value,icon,delta='8.4%',down=false){return `<article class="card kpi-card"><div class="kpi-head"><span>${label}</span><span class="kpi-icon">${icon}</span></div><h3>${value}</h3><div class="trend ${down?'down':''}"><b>${down?'↓':'↑'} ${delta}</b> vs previous period</div></article>`}
function dashboard(){
 const bars=[62,74,55,81,70,88,78,92];
 return `<div class="hero-row"><div><h1>Executive Dashboard</h1><p>Live operational position across Elevate Builders • 13 July 2026</p></div><div class="period"><button>Month</button><button class="active">Quarter</button><button>Year</button></div></div><div class="demo-notice"><b>Demonstration environment:</b> All figures and records shown below are illustrative sample data.</div>
 <div class="kpi-grid">${kpi('Contract Value','SAR 48.6M','↗','12.6%')}${kpi('Certified Revenue','SAR 28.4M','◫','9.2%')}${kpi('Gross Margin','29.2%','◉','2.1%')}${kpi('Cash Collected','SAR 21.7M','✓','4.3%',true)}</div>
 <div class="dash-grid"><article class="card"><div class="card-title"><h3>Budget vs actual cost</h3><button data-action>View analysis →</button></div><div class="chart">${bars.map((h,i)=>`<div class="bar-group"><i class="bar" style="height:${Math.min(96,h+8)}%"></i><i class="bar actual" style="height:${h}%"></i><span>${['Dec','Jan','Feb','Mar','Apr','May','Jun','Jul'][i]}</span></div>`).join('')}</div><div class="legend"><span><i></i>Actual cost</span><span><i></i>Approved budget</span></div></article>
 <article class="card"><div class="card-title"><h3>Project health</h3><button data-action>Details →</button></div><div class="donut-wrap"><div class="donut"></div><div class="status-list"><div><i style="background:#1e9b72"></i>On track <b>7</b></div><div><i style="background:#7367c7"></i>Planning <b>3</b></div><div><i style="background:#d58a1b"></i>Attention <b>1</b></div><div><i style="background:#d75a63"></i>Delayed <b>1</b></div></div></div></article></div>
 <article class="card lifecycle-card"><div class="card-title"><div><p class="section-eyebrow">END-TO-END VISIBILITY</p><h3>Business lifecycle</h3></div></div><div class="lifecycle-flow">${[
   ['12','Opportunities','Marketing qualified','teal'],
   ['5','Tenders','Financially assessed','teal'],
   ['2','Awards','Mobilization ready','gold'],
   ['6','Projects','Cost controlled','slate'],
   ['9','Billings','Progress certified','slate']
 ].map((stage,i)=>`${i?'<span class="flow-arrow">→</span>':''}<button class="flow-stage ${stage[3]}" data-action><b>${stage[0]}</b><strong>${stage[1]}</strong><small>${stage[2]}</small></button>`).join('')}</div></article>
 <div class="lower-grid"><article class="card"><div class="card-title"><h3>Priority projects</h3><button data-page-link="projects">View all projects →</button></div>${projectTable(projects.slice(0,4))}</article>
 <article class="card"><div class="card-title"><h3>Recent activity</h3><button data-action>View audit trail →</button></div>${[['✓','PO-260718 approved','Commercial Director approved SAR 186,400','8 min ago'],['⇥','Materials issued','Al Narjis Villas • 36 line items','34 min ago'],['◫','Payment certificate posted','Riyadh Logistics Hub • IPC-04','1 hr ago'],['♙','Attendance synchronized','All four project sites','2 hrs ago']].map(a=>`<div class="activity"><span>${a[0]}</span><div><b>${a[1]}</b><p>${a[2]}</p><small>${a[3]}</small></div></div>`).join('')}</article></div>`
}
function projectTable(rows){return `<div class="table-wrap"><table><thead><tr><th>PROJECT</th><th>CONTRACT VALUE</th><th>PROGRESS</th><th>STATUS</th></tr></thead><tbody>${rows.map(p=>`<tr data-action><td><div class="project-cell"><span>${p.name.charAt(0)}</span><div><b>${p.name}</b><small>${p.code} • ${p.client}</small></div></div></td><td>${p.value}</td><td><div style="display:flex;align-items:center;gap:8px"><div class="progress"><i style="width:${p.progress}%"></i></div>${p.progress}%</div></td><td><span class="badge ${p.status==='Attention'?'amber':p.status==='Delayed'?'red':''}">${p.status}</span></td></tr>`).join('')}</tbody></table></div>`}
function sar(value){return `SAR ${(value/1000000).toFixed(value%1000000?1:0)}M`}
function projectPortfolio(selected='all'){const rows=selected==='all'?costControlProjects:costControlProjects.filter(p=>p.code===selected);return `<article class="card portfolio-control"><div class="card-title"><div><p class="section-eyebrow">LIVE COST CONTROL</p><h3>Project Portfolio</h3></div><span class="badge">SAR · Jan–Dec FY</span></div><div class="table-wrap"><table><thead><tr><th>PROJECT</th><th>CONTRACT</th><th>BUDGET</th><th>ACTUAL</th><th>COMMITTED</th><th>FORECAST VARIANCE</th><th>STATUS</th></tr></thead><tbody>${rows.map(p=>`<tr><td><div class="project-cell"><span>${p.name.charAt(0)}</span><div><b>${p.name}</b><small>${p.code}</small></div></div></td><td>${sar(p.contract)}</td><td>${sar(p.budget)}</td><td>${sar(p.actual)}</td><td>${sar(p.committed)}</td><td class="${p.variance<0?'variance-negative':'variance-positive'}">${p.variance<0?'−':'+'}${sar(Math.abs(p.variance)).replace('SAR ','SAR ')}</td><td><span class="badge ${p.status==='Attention'?'red':''}">${p.status}</span></td></tr>`).join('')}</tbody></table></div></article>`}
function opportunityPipeline(shortlisted=false){const rows=shortlisted?opportunityPipelineRows.filter(o=>o.probability>=60):opportunityPipelineRows;return `<article class="card opportunity-pipeline"><div class="card-title"><div><p class="section-eyebrow">APPROVAL GATES</p><h3>Opportunity Pipeline</h3></div><button class="action-btn" data-shortlist aria-pressed="${shortlisted}">${shortlisted?'Show all':'Show shortlisted only'}</button></div><div class="table-wrap"><table><thead><tr><th>OPPORTUNITY</th><th>CLIENT</th><th>STAGE</th><th>EST. VALUE</th><th>PROBABILITY</th><th>DECISION</th></tr></thead><tbody>${rows.map(o=>`<tr><td><div class="project-cell"><span>${o.name.charAt(0)}</span><div><b>${o.name}</b><small>${o.code}</small></div></div></td><td>${o.client}</td><td><span class="badge ${o.stage==='Qualification'?'amber':''}">${o.stage}</span></td><td>${sar(o.value)}</td><td>${o.probability}%</td><td class="${o.decision==='Proceed'?'variance-positive':o.decision==='Review'?'decision-review':''}">${o.decision}</td></tr>`).join('')}</tbody></table></div></article>`}
function enhanceLifecycleOverview(page,view){if(view!=='overview')return;const focused=['marketing','projectcosting','operations'].includes(page),workflow=content.querySelector('.process-card');if(focused){content.querySelector('.overview-modules')?.remove();workflow?.remove()}if(page==='projectcosting'){const hero=content.querySelector('.hero-row'),oldButton=hero?.querySelector('[data-new-form]'),actions=document.createElement('div');actions.className='project-actions';actions.innerHTML=`<button class="action-btn primary-small" data-new-form>+ New transaction</button><label class="project-lov">Project<select data-project-filter><option value="all">All projects</option>${costControlProjects.map(p=>`<option value="${p.code}">${p.code} — ${p.name}</option>`).join('')}</select></label>`;oldButton?.remove();hero?.appendChild(actions);content.insertAdjacentHTML('beforeend',`<div class="portfolio-table-host">${projectPortfolio()}</div>`);if(workflow)content.appendChild(workflow)}if(page==='marketing'){content.insertAdjacentHTML('beforeend',`<div class="pipeline-table-host">${opportunityPipeline()}</div>`);if(workflow)content.appendChild(workflow)}if(page==='operations'&&workflow)content.appendChild(workflow)}
function savedEntries(page){const rows=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]').filter(x=>x.module===page).slice(-8).reverse();if(!rows.length)return `<article class="card saved-register"><div class="card-title"><h3>Recent entries</h3><span class="badge">Demo register</span></div><div class="empty-state">No entries yet. Open any form above to create the first demonstration record.</div></article>`;return `<article class="card saved-register"><div class="card-title"><h3>Recent entries</h3><span class="badge">${rows.length} saved</span></div><div class="table-wrap"><table><thead><tr><th>FORM / TYPE</th><th>DOCUMENT NUMBER</th><th>DATE</th><th>STATUS</th></tr></thead><tbody>${rows.map(r=>`<tr><td><b>${r.form||Object.values(r)[3]||'Transaction'}</b></td><td>${r['Document Number']||r['Reference number']||r['Tender reference']||r['Project code']||'DEMO-'+String(new Date(r.createdAt).getTime()).slice(-5)}</td><td>${new Date(r.createdAt).toLocaleDateString()}</td><td><span class="badge">Saved</span></td></tr>`).join('')}</tbody></table></div></article>`}
function lifecyclePage(page,view='overview'){const info={marketing:{intro:'Capture every potential contract, qualify it, prepare the estimate, decide whether to bid, submit the proposal and record the outcome.',kpis:[['Opportunities','12'],['Tenders Assessed','5'],['Bid Value','SAR 31.2M'],['Expected Margin','21.4%']],steps:['Opportunity','Qualification','Estimation','Bid / No-Bid Decision','Proposal & Submission','Award / Loss']},projectcosting:{intro:'Convert awarded bids into controlled project budgets, manage revisions and monitor cost and profitability through delivery.',kpis:[['Awarded Projects','6'],['Approved Budget','SAR 34.0M'],['Actual Cost','SAR 20.9M'],['Forecast Margin','18.7%']],steps:['Award','Mobilization','Baseline Budget','Operations','Budget Revision','Billing']},operations:{intro:'Execute awarded projects through connected revenue, procurement, manpower, inventory, fixed asset and expense cycles.',kpis:[['Open Purchases','14'],['Site Workforce','137'],['Stock Value','SAR 3.84M'],['Operating Spend','SAR 20.9M']],steps:['Demand','Approval','Procure / Hire','Receive','Consume','Account']}}[page];const tabs=`<div class="section-tabs"><button class="${view==='overview'?'active':''}" data-view="overview">Overview</button><button class="${view==='forms'?'active':''}" data-view="forms">Data Entry Forms</button></div>`;if(view==='forms')return `<div class="hero-row"><div><h1>${titles[page][1]}</h1><p>${info.intro}</p></div><button class="action-btn primary-small" data-new-form>+ New transaction</button></div>${tabs}<div class="module-grid forms-grid">${moduleInfo[page].map(x=>`<article class="card module-card" data-form-card data-form-key="${x[0]}"><div class="module-top"><span class="kpi-icon">${x[2]}</span><span class="badge">Entry form</span></div><h3>${x[0]}</h3><p>Create, review and save ${x[0].toLowerCase()} data for the demonstration workflow.</p><footer><b>${x[1]}</b><span>Enter data →</span></footer></article>`).join('')}</div>`;return `<div class="hero-row"><div><h1>${titles[page][1]}</h1><p>${info.intro}</p></div><button class="action-btn primary-small" data-new-form>+ New transaction</button></div>${tabs}<div class="kpi-grid">${info.kpis.map((x,i)=>kpi(x[0],x[1],['◇','▧','◫','⌁'][i],['6.8%','4.2%','9.1%','2.3%'][i])).join('')}</div><article class="card process-card"><div class="card-title"><h3>${page==='marketing'?'Opportunity-to-award workflow':page==='projectcosting'?'Award-to-delivery workflow':'Operational transaction flow'}</h3><button data-view="forms">Open forms →</button></div><div class="process-flow">${info.steps.map((s,i)=>`${i?'<span>→</span>':''}<div><b>${i+1}</b><strong>${s}</strong></div>`).join('')}</div></article><div class="module-grid overview-modules">${moduleInfo[page].slice(0,3).map(x=>`<article class="card module-card" data-view="forms"><div class="module-top"><span class="kpi-icon">${x[2]}</span><span class="badge">Live</span></div><h3>${x[0]}</h3><p>Current status and actions requiring management attention.</p><footer><b>${x[1]}</b><span>Manage →</span></footer></article>`).join('')}</div>`}
function modulePage(page){const items=moduleInfo[page],isSettings=page==='settings',tools=isSettings?'':`<div class="page-tools"><button data-action>Export</button><button class="action-btn primary-small" data-new-form>+ New transaction</button></div>`,filters=isSettings?`<div class="filters"><input placeholder="Search company, supplier, customer or setup…"></div>`:`<div class="filters"><input placeholder="Search records, documents or reference…"><select><option>All statuses</option><option>Open</option><option>Approved</option></select></div>`;return `<div class="hero-row"><div><h1>${titles[page][1]}</h1><p>${isSettings?'Maintain controlled master data used throughout transactions and reports.':'Connected information and controls for faster, accountable decisions.'}</p></div>${tools}</div>${filters}<div class="module-grid">${items.map((x,i)=>`<article class="card module-card" data-form-card data-form-key="${x[0]}"><div class="module-top"><span class="kpi-icon">${x[2]}</span><span class="badge ${i===2?'amber':''}">${page==='reports'?'Generate':i%2?'Updated today':'Live'}</span></div><h3>${x[0]}</h3><p>${page==='reports'?'Generate, preview and print this report with sample management data.':`Monitor, review and manage ${x[0].toLowerCase()} from one controlled workspace.`}</p><footer><b>${x[1]}</b><span>${page==='reports'?'Generate report':'Open form'} →</span></footer></article>`).join('')}</div>${page==='projects'?`<article class="card" style="margin-top:17px"><div class="card-title"><h3>All active projects</h3><button data-action>Portfolio report →</button></div>${projectTable(projects)}</article>`:''}`}
function companyNames(){const records=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]').filter(r=>r.module==='settings'&&r.form==='Company Setup'&&!['Suspended','Inactive'].includes(r['Record status']));return [...new Set(['Elevate Builders',...records.map(r=>r['Trading name']||r['Legal name (English)']).filter(Boolean)])]}
function refreshCompanySwitcher(){const select=document.getElementById('companySwitcher');if(!select)return;const chosen=localStorage.getItem('mustaqeem-active-company')||select.value||'Elevate Builders',names=companyNames();select.innerHTML=names.map(name=>`<option${name===chosen?' selected':''}>${name}</option>`).join('');if(!names.includes(chosen))select.value=names[0]}
function render(page,view='overview'){currentPage=page;document.querySelectorAll('.nav-item').forEach(b=>b.classList.toggle('active',b.dataset.page===page));document.getElementById('crumb').textContent=titles[page][0];document.getElementById('pageTitle').textContent=titles[page][1];content.innerHTML=page==='dashboard'?dashboard():['marketing','projectcosting','operations'].includes(page)?lifecyclePage(page,view):modulePage(page);enhanceLifecycleOverview(page,view);if((view==='forms'||['accounts','approvals','settings'].includes(page))&&page!=='reports')content.insertAdjacentHTML('beforeend',savedEntries(page));document.querySelector('.sidebar').classList.remove('open');window.scrollTo(0,0)}
function toast(message='Demo interaction completed'){const t=document.getElementById('toast');t.textContent=message;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),1900)}
function documentPrefix(page,key){const modulePrefix={marketing:'MKT',projectcosting:'PRJ',operations:'OPS',accounts:'ACC',finance:'FIN',approvals:'APR',reports:'RPT',projects:'PRJ',procurement:'PUR',inventory:'INV',workforce:'HRM',settings:'SET'}[page]||'DOC';const typePrefix={'Contract Opportunities':'OPP','Tender Register':'TEN','Cost Estimation & Scenarios':'EST','Bid / No-Bid Decision':'BND','Bid Proposals':'BID','Award / Loss Register':'AWD','Awarded Projects':'PJT','Baseline Budgets':'BUD','Budget Revisions':'BRV','WBS & Cost Codes':'WBS','Variations & Claims':'VAR','Progress & Certification':'IPC','Purchase Cycle':'PUR','HRM & Manpower':'MAN','Attendance & Payroll':'PAY','Inventory Management':'INV','Fixed Assets':'FAR','Accounts Payable':'AP','Accounts Receivable':'AR','General Ledger & Journals':'JV','Bank & Reconciliation':'BNK','Company Setup':'COM','Creditors / Suppliers':'SUP','Buyers / Customers':'CUS','Bank Accounts':'BKA','Projects & Cost Centres':'PCC','Chart of Accounts Setup':'COA','Tax Codes':'TAX','Currencies':'CUR','Payment Terms':'PMT'}[key]||'GEN';return `${modulePrefix}-${typePrefix}`}
function nextDocumentNumber(page,key){const prefix=documentPrefix(page,key),counterKey=`mustaqeem-counter-${prefix}`,next=Number(localStorage.getItem(counterKey)||1);return {counterKey,number:`${prefix}-${new Date().getFullYear()}-${String(next).padStart(5,'0')}`}}
function qualifiedOpportunities(){return JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]').filter(r=>r.form==='Contract Opportunities'&&r['Qualification decision']==='Qualified')}
function bindTenderOpportunity(){const select=document.querySelector('[name="Select qualified contract"]');if(!select)return;select.addEventListener('change',()=>{const opportunity=qualifiedOpportunities().find(r=>r['Document Number']===select.value);if(!opportunity)return;const mapping={'Contract number':'Contract number','Contract type':'Contract type','Prospective client':'Prospective client','Opportunity received date':'Date received','Estimated contract value (SAR)':'Estimated contract value (SAR)','Project location':'Project location','Scope summary':'Scope summary'};Object.entries(mapping).forEach(([target,source])=>{const field=document.querySelector(`[name="${target}"]`);if(field)field.value=opportunity[source]||''})})}
function bindVatCalculation(){const taxable=document.querySelector('[name="Taxable amount excluding VAT (SAR)"]'),treatment=document.querySelector('[name="VAT treatment"]'),rate=document.querySelector('[name="VAT rate (%)"]'),vat=document.querySelector('[name="VAT amount (SAR)"]'),total=document.querySelector('[name="Total including VAT (SAR)"]');if(!taxable||!treatment||!rate||!vat||!total)return;const calculate=()=>{const base=Number(taxable.value||0),percentage=treatment.value==='Standard-rated 15%'?15:0,tax=base*percentage/100;rate.value=percentage.toFixed(2);vat.value=tax.toFixed(2);total.value=(base+tax).toFixed(2)};taxable.addEventListener('input',calculate);treatment.addEventListener('change',calculate);calculate()}
function bindCoaImport(){const input=document.getElementById('coaExcelUpload'),status=document.getElementById('coaImportStatus');if(!input)return;input.addEventListener('change',async()=>{const file=input.files[0];if(!file)return;try{status.textContent='Reading and validating workbook…';const workbook=XLSX.read(await file.arrayBuffer(),{type:'array'}),sheet=workbook.Sheets['Chart of Accounts']||workbook.Sheets[workbook.SheetNames[0]],rows=XLSX.utils.sheet_to_json(sheet,{range:3,defval:''});if(!rows.length||!('Account Code' in rows[0])||!('Account Name' in rows[0]))throw new Error('Required columns Account Code and Account Name were not found.');const saved=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]').filter(r=>!(r.module==='settings'&&r.form==='Chart of Accounts Setup'&&String(r['Document Number']||'').startsWith('SET-COA-IMP-'))),validRows=rows.filter(r=>r['Account Code']&&r['Account Name']);const typeFromCode=code=>({1:'Asset',2:'Liability',3:'Equity',4:'Revenue',5:'Cost of Sales',6:'Expense',7:'Revenue',8:'Asset'}[String(code)[0]]||'Expense');validRows.forEach(r=>saved.push({module:'settings',form:'Chart of Accounts Setup',createdAt:new Date().toISOString(),'Document Number':`SET-COA-IMP-${r['Account Code']}`,'Account code':String(r['Account Code']),'Account name':r['Account Name'],'Arabic account name':'','Account type':typeFromCode(r['Account Code']),'Parent account':String(r['Parent Code']||''),'Posting type':r['Posting Type']||'Posting','Normal balance':r['Normal Balance']||'Debit','Project required':r['Project Required']==='Required'?'Yes':'No','VAT code required':r['Default VAT Code']&&r['Default VAT Code']!=='No VAT'?'Yes':'No','Reconciliation type':'None','Active':'Yes'}));localStorage.setItem('mustaqeem-demo-records',JSON.stringify(saved));input.disabled=true;status.textContent=`Imported ${validRows.length} accounts successfully. Returning to Settings…`;setTimeout(()=>{closeForm();render('settings');toast(`${validRows.length} chart-of-account records imported`)},700)}catch(error){status.textContent=`Import failed: ${error.message}`}})}
function bindPartyMaster(key){const isSupplier=key==='Accounts Payable',select=document.querySelector(`[name="${isSupplier?'Supplier legal name':'Customer legal name'}"]`);if(!select)return;select.addEventListener('change',()=>{const records=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]'),record=records.find(r=>r.module==='settings'&&r.form===(isSupplier?'Creditors / Suppliers':'Buyers / Customers')&&r[isSupplier?'Supplier legal name':'Customer legal name']===select.value);if(!record)return;const mapping=isSupplier?{'Supplier VAT registration number (15 digits)':'Supplier VAT number','Payment terms':'Default payment term','Expense / asset account':'Default expense account'}:{'Customer VAT registration number (15 digits)':'Customer VAT number','Payment terms':'Default payment term','Revenue account':'Default revenue account'};Object.entries(mapping).forEach(([target,source])=>{const field=document.querySelector(`[name="${target}"]`);if(field&&record[source]){const option=[...field.options||[]].find(x=>x.value===record[source]);if(option||field.tagName!=='SELECT')field.value=record[source]}})})}
function bindCompanyLogo(){const input=document.querySelector('.company-logo-field input[type="file"]'),hidden=document.getElementById('companyLogoData'),preview=document.getElementById('companyLogoPreview');if(!input)return;input.addEventListener('change',()=>{const file=input.files[0];if(!file)return;const reader=new FileReader();reader.onload=()=>{const image=new Image();image.onload=()=>{const scale=Math.min(1,300/image.width,120/image.height),canvas=document.createElement('canvas');canvas.width=Math.round(image.width*scale);canvas.height=Math.round(image.height*scale);canvas.getContext('2d').drawImage(image,0,0,canvas.width,canvas.height);hidden.value=canvas.toDataURL('image/jpeg',.85);preview.src=hidden.value;preview.classList.remove('hidden')};image.src=reader.result};reader.readAsDataURL(file)})}
function setupValues(spec){const [formKey,labelField]=spec.split('|'),records=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]').filter(r=>r.module==='settings'&&r.form===formKey&&(!r.Active||r.Active==='Yes')&&!['Blocked','Inactive'].includes(r.Status)&&(formKey!=='Chart of Accounts Setup'||r['Posting type']!=='Header'));const values=[...new Set(records.map(r=>formKey==='Chart of Accounts Setup'?`${r['Account code']} - ${r['Account name']}`:r[labelField]).filter(Boolean))];const defaults={'Company Setup':['Elevate Builders'],'Creditors / Suppliers':['Sample Material Supplier','Sample Subcontractor'],'Buyers / Customers':['Al Noor Development','Gulf Industrial Co.'],'Bank Accounts':['SA00 0000 0000 0000 0000 0000'],'Projects & Cost Centres':['North Riyadh Villas','Metro Station Fit-out','Head Office'],'Chart of Accounts Setup':constructionCoa,'Tax Codes':['Standard-rated 15%','Zero-rated 0%','Exempt','Outside scope'],'Currencies':['SAR','USD','EUR','GBP'],'Payment Terms':['Immediate','30 Days','60 Days']}[formKey]||[];return values.length?values:defaults}
function openForm(page=currentPage,key=''){const config=detailedForms[key]||formConfigs[page]||formConfigs.projects,doc=nextDocumentNumber(page,key),fields=[['Document Number','auto'],...config.fields.filter(f=>f[0].toLowerCase()!=='document number')],opportunities=qualifiedOpportunities();const form=document.getElementById('entryForm');form.dataset.formKey=key;form.dataset.counterKey=doc.counterKey;document.getElementById('formTitle').textContent=config.title;document.getElementById('formFields').innerHTML=fields.map((f,i)=>{const id=`field-${i}`,wide=['textarea','readonlyarea'].includes(f[1])?' wide':'';if(f[1]==='auto')return `<label>${f[0]}<input id="${id}" name="${f[0]}" type="text" value="${doc.number}" readonly required><small class="field-help">Automatically generated by MUSTAQEEM</small></label>`;if(f[1]==='opportunity-select')return `<label class="wide">${f[0]}<select id="${id}" name="${f[0]}" required><option value="">${opportunities.length?'Select a qualified contract…':'No qualified contract available — qualify an opportunity first'}</option>${opportunities.map(r=>`<option value="${r['Document Number']}">${r['Document Number']} — ${r['Opportunity title']} — ${r['Prospective client']}</option>`).join('')}</select><small class="field-help">Only opportunities qualified by Director Planning are available.</small></label>`;if(f[1]==='readonly')return `<label>${f[0]}<input id="${id}" name="${f[0]}" type="text" readonly required></label>`;if(f[1]==='readonlyarea')return `<label class="wide">${f[0]}<textarea id="${id}" name="${f[0]}" rows="3" readonly required></textarea></label>`;if(f[1]==='image')return '<label class="wide company-logo-field">'+f[0]+'<input id="'+id+'" type="file" accept="image/png,image/jpeg" required><input id="companyLogoData" name="'+f[0]+'" type="hidden"><img id="companyLogoPreview" class="company-logo-preview hidden" alt="Company logo preview"><small class="field-help">PNG or JPEG company logo</small></label>';if(f[1]==='setup-select')return `<label class="${wide}">${f[0]}<select id="${id}" name="${f[0]}" required><option value="">Select from setup…</option>${setupValues(f[2]).map(x=>`<option>${x}</option>`).join('')}</select><small class="field-help">Maintained under Settings &amp; Setups</small></label>`;if(f[1]==='select')return `<label class="${wide}">${f[0]}<select id="${id}" name="${f[0]}" required><option value="">Select…</option>${f[2].split('|').map(x=>`<option>${x}</option>`).join('')}</select></label>`;if(f[1]==='textarea')return `<label class="wide">${f[0]}<textarea id="${id}" name="${f[0]}" rows="3" required></textarea></label>`;return `<label class="${wide}">${f[0]}<input id="${id}" name="${f[0]}" type="${f[1]}" ${f[1]==='number'?'min="0" step="any"':''} required></label>`}).join('');if(key==='Chart of Accounts Setup'){document.getElementById('formFields').insertAdjacentHTML('afterbegin',`<section class="coa-import"><h3>Import Excel Chart of Accounts</h3><p>Upload the MUSTAQEEM workbook. The first worksheet must contain Account Code and Account Name columns.</p><input id="coaExcelUpload" type="file" accept=".xlsx,.xls"><span id="coaImportStatus" class="coa-import-status">No file selected.</span></section>`);bindCoaImport()}if(key==='Tender Register')bindTenderOpportunity();if(['Accounts Payable','Accounts Receivable','VAT & Tax Entries'].includes(key))bindVatCalculation();if(['Accounts Payable','Accounts Receivable'].includes(key))bindPartyMaster(key);if(key==='Company Setup')bindCompanyLogo();document.getElementById('formModal').classList.remove('hidden');setTimeout(()=>document.querySelector('#formFields input:not([readonly]), #formFields select')?.focus(),50)}
function closeForm(){const form=document.getElementById('entryForm');document.getElementById('formModal').classList.add('hidden');form.reset();delete form.dataset.module}
const quickPanel=document.getElementById('quickPanel'),quickPanelTitle=document.getElementById('quickPanelTitle'),quickPanelLabel=document.getElementById('quickPanelLabel'),quickPanelBody=document.getElementById('quickPanelBody');
const searchIndex=[['dashboard','Executive Dashboard','Portfolio KPIs, cost performance and management actions'],['marketing','Marketing & Tendering','Opportunities, qualification, estimates and bid proposals'],['projectcosting','Projects & Costing','Project budgets, revisions, progress and profitability'],['operations','Operations & Modules','Purchasing, manpower, inventory and assets'],['accounts','Accounts','Journals, payables, receivables, VAT and bank reconciliation'],['finance','Finance','Revenue, project costs, margins and cash forecast'],['approvals','Approvals','Pending management approvals'],['reports','Reports','Management and financial reports'],['settings','Settings & Setups','Company, suppliers, customers, banks, accounts and tax codes']];
function closeQuickPanel(){quickPanel.classList.add('hidden')}
function showSearch(){quickPanelLabel.textContent='GLOBAL SEARCH';quickPanelTitle.textContent='Find a page or transaction';quickPanelBody.innerHTML=`<div class="quick-search"><input id="quickSearchInput" placeholder="Search modules, forms or records…" autocomplete="off"></div><div id="quickResults" class="quick-results"></div>`;quickPanel.classList.remove('hidden');const input=document.getElementById('quickSearchInput'),results=document.getElementById('quickResults');const draw=()=>{const q=input.value.trim().toLowerCase(),matches=searchIndex.filter(x=>!q||`${x[1]} ${x[2]}`.toLowerCase().includes(q));results.innerHTML=matches.length?matches.map(x=>`<button class="quick-result" data-page="${x[0]}"><b>${x[1]}</b><small>${x[2]}</small></button>`).join(''):'<div class="panel-empty">No matching page found.</div>'};input.addEventListener('input',draw);draw();setTimeout(()=>input.focus(),30)}
function showNotifications(){quickPanelLabel.textContent='ACTION CENTRE';quickPanelTitle.textContent='Notifications';quickPanelBody.innerHTML=`<div class="notification-list"><button class="notification-item unread" data-page="approvals"><b>7 approvals require review</b><small>Purchase orders, payments and budget revisions</small></button><button class="notification-item unread" data-page="accounts"><b>3 supplier invoices need matching</b><small>PO and GRN verification is pending</small></button><button class="notification-item" data-page="marketing"><b>Bid submission due in 2 days</b><small>Riyadh Commercial Complex</small></button><button class="notification-item" data-page="projectcosting"><b>Budget variance requires attention</b><small>Metro Station Fit-out</small></button></div>`;quickPanel.classList.remove('hidden')}
function showSettings(){const setups=[['Company Setup','Legal entity and Saudi registrations'],['Creditors / Suppliers','Supplier master and payment controls'],['Buyers / Customers','Customer master and billing controls'],['Bank Accounts','Company bank and IBAN master'],['Projects & Cost Centres','Project and cost allocation setup'],['Chart of Accounts Setup','Ledger accounts and Excel import'],['Tax Codes','Saudi VAT and tax treatments'],['Currencies','Transaction currencies and rates'],['Payment Terms','Customer and supplier payment terms']];quickPanelLabel.textContent='MASTER DATA';quickPanelTitle.textContent='Settings & Setups';quickPanelBody.innerHTML=`<div class="notification-list">${setups.map(x=>`<button class="notification-item" data-setup-form="${x[0]}"><b>${x[0]}</b><small>${x[1]}</small></button>`).join('')}</div>`;quickPanel.classList.remove('hidden')}
document.getElementById('globalSearch').addEventListener('click',showSearch);
document.getElementById('notifications').addEventListener('click',showNotifications);
document.getElementById('settingsShortcut').addEventListener('click',showSettings);
document.getElementById('closeQuickPanel').addEventListener('click',closeQuickPanel);
quickPanel.addEventListener('click',e=>{const setup=e.target.closest('[data-setup-form]');if(setup){closeQuickPanel();openForm('settings',setup.dataset.setupForm);document.getElementById('entryForm').dataset.module='settings'}if(e.target.closest('[data-page]'))setTimeout(closeQuickPanel,0)});
document.getElementById('signIn').onclick=()=>{document.getElementById('login').classList.add('hidden');document.getElementById('app').classList.remove('hidden');refreshCompanySwitcher();render('dashboard')};
document.getElementById('companySwitcher').addEventListener('change',e=>{localStorage.setItem('mustaqeem-active-company',e.target.value);e.target.classList.remove('company-changed');void e.target.offsetWidth;e.target.classList.add('company-changed');toast(`Active company changed to ${e.target.value}`)});
document.getElementById('logout').onclick=()=>{document.getElementById('app').classList.add('hidden');document.getElementById('login').classList.remove('hidden')};
document.getElementById('menuToggle').onclick=()=>document.querySelector('.sidebar').classList.toggle('open');
document.addEventListener('click',e=>{const n=e.target.closest('[data-page]');if(n)render(n.dataset.page);const l=e.target.closest('[data-page-link]');if(l)render(l.dataset.pageLink);const view=e.target.closest('[data-view]');if(view)render(currentPage,view.dataset.view);const formCard=e.target.closest('[data-form-card]');if(formCard)openForm(currentPage,formCard.dataset.formKey);else if(e.target.closest('[data-new-form]'))openForm();const shortlist=e.target.closest('[data-shortlist]');if(shortlist){const next=shortlist.getAttribute('aria-pressed')!=='true';document.querySelector('.pipeline-table-host').innerHTML=opportunityPipeline(next)}const period=e.target.closest('.period button');if(period){document.querySelectorAll('.period button').forEach(x=>x.classList.remove('active'));period.classList.add('active');toast(`Period changed to ${period.textContent}`)}const action=e.target.closest('[data-action]');if(action)toast();if(e.target.closest('[data-close-modal]'))closeForm();if(e.target.closest('[data-print-report]'))window.print()});
document.addEventListener('change',e=>{if(e.target.matches('[data-project-filter]'))document.querySelector('.portfolio-table-host').innerHTML=projectPortfolio(e.target.value)});
document.addEventListener('input',e=>{if(e.target.matches('.filters input')){const q=e.target.value.trim().toLowerCase();document.querySelectorAll('.module-grid .module-card').forEach(card=>card.hidden=Boolean(q)&&!card.textContent.toLowerCase().includes(q))}});
function reportPreview(record){content.innerHTML=`<div class="hero-row"><div><p class="section-eyebrow">GENERATED MANAGEMENT REPORT</p><h1>${record.Report||'Management Report'}</h1><p>${record['Period from']||'01-Jul-2026'} to ${record['Period to']||'31-Jul-2026'} • ${record.Project||'All Projects'}</p></div><div class="page-tools"><button data-page="reports">← Reports</button><button class="action-btn primary-small" data-print-report>Print / Save PDF</button></div></div><div class="kpi-grid">${kpi('Contract Value','SAR 48.6M','↗','12.6%')}${kpi('Revenue','SAR 28.4M','◫','9.2%')}${kpi('Actual Cost','SAR 20.9M','↘','5.8%')}${kpi('Forecast Margin','18.7%','⌁','2.1%')}</div><article class="card"><div class="card-title"><h3>Project performance summary</h3><span class="badge">Sample data</span></div>${projectTable(projects)}</article>`}
document.getElementById('entryForm').addEventListener('submit',e=>{e.preventDefault();const record=Object.fromEntries(new FormData(e.target)),counterKey=e.target.dataset.counterKey,page=e.target.dataset.module||currentPage;const saved=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]');saved.push({module:page,form:e.target.dataset.formKey,createdAt:new Date().toISOString(),...record});localStorage.setItem('mustaqeem-demo-records',JSON.stringify(saved));if(counterKey)localStorage.setItem(counterKey,String(Number(localStorage.getItem(counterKey)||1)+1));const isReport=page==='reports';closeForm();delete e.target.dataset.module;if(isReport){reportPreview(record);toast('Report generated successfully')}else if(page==='settings'){toast(`Record ${record['Document Number']} saved successfully`)}else{render(page,['marketing','projectcosting','operations'].includes(page)?'forms':'overview');toast(`Record ${record['Document Number']} saved successfully`)}});
document.getElementById('entryForm').addEventListener('submit',e=>{if(e.target.dataset.formKey==='Company Setup')setTimeout(refreshCompanySwitcher,0)});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeForm()});
